vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = 0.6 + (vUv-0.5)*(vec2(0.1,-0.9)*cos(uTime)*0.1+0.5) - vec2((audioLow*0.01),0.05);
    vec3 base = GetBlur3(vUv) + GetBlur2(vUv) * GetBlur1(vUv) + sin(uTime+(texture(sampler_main, vUv))) + 0.04;
a =base.x/4;b = base.y/4; c = base.z/4;
c = c + b - c*b;
a = a + c - a*c;
base = 1.4*a;
ret = base*(1-base)*(1-base)*2*vec3(2,1.4,0) + pow(base,2)*vec3(-0.3,0.2,0.6);
//ret.xy = ret.yx;

  fragColor = ret;
}
